def safe_tool_execute(tool_func, args):
    try:
        return tool_func(**args)
    except Exception as e:
        return f"Error during execution: {str(e)}"

def run_practice():
    def failing_tool():
        raise ValueError("Connection failed")
    res = safe_tool_execute(failing_tool, {})
    assert "ValueError" in res or "Connection" in res
    print('[PASS] Exception capture safety checks validated.')

if __name__ == '__main__':
    run_practice()
